    auto N = x.size(0);
    auto C_in = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    auto C_out = weight.size(0);
    auto K_h = weight.size(2);
    auto K_w = weight.size(3);
    auto H_out = H - K_h + 1;
    auto W_out = W - K_w + 1;
    at::Tensor y = at::empty({N, C_out, H_out, W_out}, x.options());

    EXEC_NPU_CMD(aclnnConvStandard2dSquareInputSquareKernelCustom, x, weight, y);
    return y;
